import{_ as a,c as e,o,a4 as r}from"./chunks/framework.HaEZziQ1.js";const t="/FrontEndLearnNotes/assets/image-20240306201052865.DVDisQLw.png",n="/FrontEndLearnNotes/assets/image-20240306201113576.02qC-Mwi.png",f=JSON.parse('{"title":"前端工具环境配置","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端开发环境配置/前端工具环境配置.md","filePath":"Document/前端开发环境配置/前端工具环境配置.md","lastUpdated":null}'),s={name:"Document/前端开发环境配置/前端工具环境配置.md"},l=r(`<h1 id="前端工具环境配置" tabindex="-1">前端工具环境配置 <a class="header-anchor" href="#前端工具环境配置" aria-label="Permalink to &quot;前端工具环境配置&quot;">​</a></h1><p>参考：<a href="https://juejin.cn/post/7187272143657730108?" target="_blank" rel="noreferrer">https://juejin.cn/post/7187272143657730108?</a></p><h2 id="开发软件" tabindex="-1">开发软件 <a class="header-anchor" href="#开发软件" aria-label="Permalink to &quot;开发软件&quot;">​</a></h2><h3 id="visual-studio-code" tabindex="-1">Visual Studio Code <a class="header-anchor" href="#visual-studio-code" aria-label="Permalink to &quot;Visual Studio Code&quot;">​</a></h3><p>Visual Studio Code官网地址：<a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code - Code Editing. Redefined</a></p><h3 id="webstorm" tabindex="-1">WebStorm <a class="header-anchor" href="#webstorm" aria-label="Permalink to &quot;WebStorm&quot;">​</a></h3><p>WebStorm官网地址：<a href="https://www.jetbrains.com/guide/javascript/" target="_blank" rel="noreferrer">JavaScript and TypeScript - JetBrains Guide</a></p><h2 id="配置开发环境" tabindex="-1">配置开发环境 <a class="header-anchor" href="#配置开发环境" aria-label="Permalink to &quot;配置开发环境&quot;">​</a></h2><h3 id="node版本管理工具-nvm" tabindex="-1">Node版本管理工具：nvm <a class="header-anchor" href="#node版本管理工具-nvm" aria-label="Permalink to &quot;Node版本管理工具：nvm&quot;">​</a></h3><p>工作中的项目有很多老项目，需要在不同版本的Node.js中运行，项目在稳定上线后通常就不会再去更新其 node 版本和依赖模块的版本，所以我们需要一个工具来为不同的项目配置不同的 node 版本。</p><blockquote><p>下载地址：<a href="https://github.com/coreybutler/nvm-windows/releases" target="_blank" rel="noreferrer">Releases · coreybutler/nvm-windows (github.com)</a></p><p>github：<a href="https://github.com/coreybutler/nvm-windows" target="_blank" rel="noreferrer">coreybutler/nvm-windows: A node.js version management utility for Windows. Ironically written in Go. (github.com)</a></p></blockquote><p><strong>注意事项：</strong></p><ol><li>尽量先安装 nvm， 通过 nvm 安装 node.js，如果先安装了 node.js，要在 nvm 安装过程中正确配置 node.js 的路径。</li><li>安装完毕后直接在命令行使用会提示 &#39;nvm&#39;/&#39;node&#39; 不是内部或外部命令，也不是可运行的程序，搜一下跟着网上教程配置环境变量即可。<strong>不过这里要注意的是，公司电脑可能会禁止打开编辑系统环境变量</strong>，通过 <strong>控制面板-&gt;用户账户-&gt;更改我的环境变量</strong> 打开即可。</li><li>配置环境变量 <code>PATH</code> 时可以把 <strong>nodejs 目录下的 node_global 文件夹</strong>也添加进去，这个文件夹存放的是全局安装的模块。这样的话日后安装如 <code>yarn</code> 、<code>whistle</code> 等模块时无需再单独配置环境变量即可在命令行中使用其命令。</li></ol><h3 id="node版本管理工具-volta" tabindex="-1">Node版本管理工具：volta <a class="header-anchor" href="#node版本管理工具-volta" aria-label="Permalink to &quot;Node版本管理工具：volta&quot;">​</a></h3><p>开源地址：<a href="https://github.com/volta-cli/volta" target="_blank" rel="noreferrer">volta-cli/volta: Volta: JS Toolchains as Code. ⚡ (github.com)</a></p><p>官网：<a href="https://volta.sh/" target="_blank" rel="noreferrer">Volta - The Hassle-Free JavaScript Tool Manager</a></p><h3 id="node-npm" tabindex="-1">node / npm <a class="header-anchor" href="#node-npm" aria-label="Permalink to &quot;node / npm&quot;">​</a></h3><p>当通过 nvm 安装好 node 之后，我们要把 npm 的下载源换成公司的：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 查看下载源： https://registry.npmjs.org/</span></span>
<span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> config</span><span style="color:#98C379;"> get</span><span style="color:#98C379;"> registry</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 切换 npm 下载源到京东</span></span>
<span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> config</span><span style="color:#98C379;"> set</span><span style="color:#98C379;"> registry</span><span style="color:#98C379;"> http://npm.m.jd.com/mirrors</span></span>
<span class="line"><span style="color:#61AFEF;">yarn</span><span style="color:#98C379;"> config</span><span style="color:#98C379;"> set</span><span style="color:#98C379;"> registry</span><span style="color:#98C379;"> http://npm.m.jd.com/mirrors</span></span>
<span class="line"><span style="color:#61AFEF;">pnpm</span><span style="color:#98C379;"> config</span><span style="color:#98C379;"> set</span><span style="color:#98C379;"> registry</span><span style="color:#98C379;"> http://npm.m.jd.com/mirrors</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 淘宝源</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="⭐-git" tabindex="-1">⭐ git <a class="header-anchor" href="#⭐-git" aria-label="Permalink to &quot;⭐ git&quot;">​</a></h3><p>Git 官网：<a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git (git-scm.com)</a></p><h4 id="ssh" tabindex="-1">ssh <a class="header-anchor" href="#ssh" aria-label="Permalink to &quot;ssh&quot;">​</a></h4><p>安装好 git 之后我们就可以拉取远程仓库的代码了，但是在拉取公司项目代码之前还差一步——生成 SSH 密钥。</p><blockquote><p>SSH密钥用于SSH协议中的密钥认证，提供一种安全的方式来进行远程登录或其他网络服务。它包括一对密钥：一个私钥（保密）和一个公钥（可以公开）。公钥放在远程服务器上，私钥由用户安全保管。当用户尝试连接到服务器时，服务器使用公钥来验证用户的私钥，如果匹配，则授予访问权限，无需输入密码。这种方式比传统密码认证更安全。</p></blockquote><p>如果公司有自己的代码仓库，会对生成并上传 SSH 有教程。</p><h2 id="编程插件配置" tabindex="-1">编程插件配置 <a class="header-anchor" href="#编程插件配置" aria-label="Permalink to &quot;编程插件配置&quot;">​</a></h2><p><a href="https://juejin.cn/post/7331928379555971111" target="_blank" rel="noreferrer">【JSDoc】都2024年了，你不会还在用纯文本写注释吧 - 掘金 (juejin.cn)</a></p><h3 id="visual-studio-code插件配置" tabindex="-1">Visual Studio Code插件配置 <a class="header-anchor" href="#visual-studio-code插件配置" aria-label="Permalink to &quot;Visual Studio Code插件配置&quot;">​</a></h3><h4 id="插件-rest-client" tabindex="-1">插件：REST Client <a class="header-anchor" href="#插件-rest-client" aria-label="Permalink to &quot;插件：REST Client&quot;">​</a></h4><p>我们在开发测试接口时一般会使用 <code>Postman</code> 等接口调试工具测试，需要设置 <code>URL</code>、<code>token</code>、<code>headers</code> 等，但是对于前端来说，我们可能只关心这个接口的入参还有返回值，不想去配置那么多东西，或者不想用 <code>Postman</code> 但又需要测试接口，有时候可能是不停地去页面点击或者刷新页面发起请求，这时候就会很麻烦。那这里有一个简单场景下的接口测试工具，适合使用 vscode 开发的同学。</p><h4 id="数据库可视化连接插件-database-client" tabindex="-1">数据库可视化连接插件：Database Client <a class="header-anchor" href="#数据库可视化连接插件-database-client" aria-label="Permalink to &quot;数据库可视化连接插件：Database Client&quot;">​</a></h4><p>安装了之后，就会在 vscode 左侧生成两个图标，上面一个表示关系型，下面一个表示非关系型。你可以连接你的本地数据库服务，进行开发调试</p><h2 id="开发助力工具" tabindex="-1">开发助力工具 <a class="header-anchor" href="#开发助力工具" aria-label="Permalink to &quot;开发助力工具&quot;">​</a></h2><h3 id="whistle" tabindex="-1">whistle <a class="header-anchor" href="#whistle" aria-label="Permalink to &quot;whistle&quot;">​</a></h3><p>文档：<a href="https://wproxy.org/whistle/install.html" target="_blank" rel="noreferrer">安装启动 · GitBook (wproxy.org)</a></p><p>企业中前后端开发进度经常会不一致，有时候后端的接口还没上线，但我们做完了页面想自己测试一下效果，可以通过 whistle 抓包来自己模拟数据。</p><h3 id="switchhosts" tabindex="-1">SwitchHosts <a class="header-anchor" href="#switchhosts" aria-label="Permalink to &quot;SwitchHosts&quot;">​</a></h3><p>GitHub 地址：<a href="https://wproxy.org/whistle/install.html" target="_blank" rel="noreferrer">安装启动 · GitBook (wproxy.org)</a></p><p>其实直接修改 hosts 文件也可以，但 SwtichHosts 会方便一些。</p><p>有时公司后端的服务器只会响应来自特定域名的请求，比如京东的后台只响应 <code>xxx.jd.com</code> 这种以 <code>jd.com</code> 结尾的域名发起的请求，这就需要我们通过配置 webpack 的 host 为 <code>xxx.jd.com</code>，同时用 hosts 文件把 <code>xxx.jd.com</code> 解析到 <strong>127.0.0.1</strong> 上。</p><h2 id="抓包工具" tabindex="-1">抓包工具 <a class="header-anchor" href="#抓包工具" aria-label="Permalink to &quot;抓包工具&quot;">​</a></h2><h3 id="_1-抓包工具-proxyman" tabindex="-1">1.抓包工具 Proxyman <a class="header-anchor" href="#_1-抓包工具-proxyman" aria-label="Permalink to &quot;1.抓包工具 Proxyman&quot;">​</a></h3><p>不了解抓包工具的童鞋还不知道抓包工具的强大。简单举个例子：</p><ul><li>你们公司开发的系统部署给客户了，现场交付的同学给你说系统出现了故障，接口似乎出错了</li><li>但是用户是内网环境，各种各样的原因你又没办法远程或者 <code>vpn</code> 连接客户的电脑排查问题</li><li>此时你又必须要查看接口具体是入参错误还是接口调用错误，必须得有接口信息你才能排查</li></ul><p>怎么办？此时你需要先知道一个东西，<code>HTTP</code> 存档：<code>HAR</code>。</p><blockquote><p>HAR（HTTP 存档 ） 规范定义了 HTTP 事务的存档格式，是多种 HTTP 会话工具用来导出所记录数据的 一种文件格式，Web 浏览器可以使用该格式导出有关其加载的网页的详细性能数据。</p></blockquote><p>在浏览器接口列表里右键某个接口，会出现以下选项：</p><p><img src="`+t+'" alt="image-20240306201052865"></p><p>点击保存为 <code>HAR</code>，浏览器会为你将当前页的所有接口保存为一个 <code>HAR</code> 包。此时你可以让客户现场的同学将报错的接口保存为 <code>HAR</code> 包并发送给你，你可以使用类似 <code>Proxyman</code> 的抓包工具打开，来看看打开的效果：</p><p><img src="'+n+'" alt="image-20240306201113576"></p><p>和浏览器的 <code>Network</code> 界面是几乎一模一样的，这时候你就可以尽情排查问题，而不再因为 <code>vpn</code>、远程无法连接客户电脑而焦虑了。</p><p>当然了，抓包工具有很多，这里介绍 <code>Proxyman</code> 是因为它的 UI 界面简洁优美。还有就是抓包工具的用法不仅仅是这个，这只是一个比较基础的应用，更多用法这里不再赘述，以后有机会开专题来说说抓包工具的问题。</p><h2 id="实用工具" tabindex="-1">实用工具 <a class="header-anchor" href="#实用工具" aria-label="Permalink to &quot;实用工具&quot;">​</a></h2><h3 id="gifcam" tabindex="-1">GifCam <a class="header-anchor" href="#gifcam" aria-label="Permalink to &quot;GifCam&quot;">​</a></h3><p>GifCam | GIF 录制工具：<a href="https://blog.bahraniapps.com/gifcam/#download" target="_blank" rel="noreferrer">GifCam | BahraniApps Blog</a></p><p>非常好用的 <strong>gif 录制工具</strong>，之前写掘金想展示前端代码效果的时候接触到的。工作中有时候想和产品或者 UI 确认一些细节效果，不想拉会议投屏，录个 gif 是很好的选择。</p><h3 id="easy-mock-在线接口服务" tabindex="-1">Easy Mock 在线接口服务 <a class="header-anchor" href="#easy-mock-在线接口服务" aria-label="Permalink to &quot;Easy Mock 在线接口服务&quot;">​</a></h3><p><a href="https://mock.mengxuegu.com/login" target="_blank" rel="noreferrer">Easy Mock (mengxuegu.com)</a></p><p>后端写接口磨磨蹭蹭？自己 <code>mock</code> 数据又麻烦？也不想用 <code>json-server</code> 或者 <code>node</code> 启动本地服务调试？那这个网站或许适合你，先拿到和后端商量好的数据格式及字段，然后在 <code>Easy Mock</code> 上定义对应的接口和数据，你可以使用 <code>mockjs</code> 语法生成随机数据，也可以使用静态数据。在你需要批量化的假数据填充表格的时候，这个工具非常有用。还可以结合 <code>mockjs</code> 语法进行函数编写，使用函数接收入参并控制返回数据。</p><h3 id="json-在线工具" tabindex="-1">JSON 在线工具 <a class="header-anchor" href="#json-在线工具" aria-label="Permalink to &quot;JSON 在线工具&quot;">​</a></h3><p><a href="https://www.json.cn/" target="_blank" rel="noreferrer">JSON在线解析及格式化验证 - JSON.cn</a></p><p>一个功能非常丰富的 JSON 在线工具网站，可以在线格式化 JSON 字符串，在线进行代码对比，能做非常多你想得到想不到的事 —— 它还可以在线运行 C++、C、Java 等语言代码，还可以压缩图片，IP 查询等，简直就是万能百宝箱。</p><h3 id="在线打字练习" tabindex="-1">在线打字练习 <a class="header-anchor" href="#在线打字练习" aria-label="Permalink to &quot;在线打字练习&quot;">​</a></h3><p>如果你还在为打字不快而烦恼，想要练习却又无从下手，现在好了，下面两个打字练习网站可以帮助你练习正确的打字姿势，快速记住键位，进行多样化的打字练习。</p><p><a href="https://www.keybr.com/" target="_blank" rel="noreferrer">Typing Practice (keybr.com)</a></p><p>帮助你快速熟悉键位。</p><p><a href="https://dazigo.vip/" target="_blank" rel="noreferrer">在线打字测试(打字狗 dazigo.vip)</a></p><p>在这里你可以进行键位练习、打字比赛、打字排行、打字游戏。海量文章古诗随意挑选进行练习，是综合功能最全、最好用的免费打字网站之一。</p><h2 id="其他优秀的前端学习网站" tabindex="-1">其他优秀的前端学习网站 <a class="header-anchor" href="#其他优秀的前端学习网站" aria-label="Permalink to &quot;其他优秀的前端学习网站&quot;">​</a></h2><p><a href="https://luvsunlight.github.io/js-offer-algo/#/" target="_blank" rel="noreferrer">js剑指offer题解 (luvsunlight.github.io)</a></p><p><a href="https://ustbhuangyi.github.io/vue-analysis/" target="_blank" rel="noreferrer">前言 | Vue.js 技术揭秘 (ustbhuangyi.github.io)</a></p><p><a href="https://webpack.wuhaolin.cn/" target="_blank" rel="noreferrer">深入浅出 Webpack · 深入浅出 Webpack (wuhaolin.cn)</a></p><p><a href="https://es6.ruanyifeng.com/#README" target="_blank" rel="noreferrer">ES6 入门教程 - ECMAScript 6入门 (ruanyifeng.com)</a></p><p><a href="https://blog.poetries.top/browser-working-principle/" target="_blank" rel="noreferrer">浏览器工作原理与实践 (poetries.top)</a></p><h2 id="开放接口" tabindex="-1">开放接口 <a class="header-anchor" href="#开放接口" aria-label="Permalink to &quot;开放接口&quot;">​</a></h2><h3 id="聚合api" tabindex="-1">聚合API <a class="header-anchor" href="#聚合api" aria-label="Permalink to &quot;聚合API&quot;">​</a></h3><p>该网站提供了大量的免费的 <code>API</code> 接口供我们使用,大家可以将其用在自己的项目上使用,并且每个接口都提供了完整的文档,开箱即用。</p><p>官网：<a href="https://www.free-api.com/" target="_blank" rel="noreferrer">接口大全-免费API,收集所有免费的API (free-api.com)</a></p><h3 id="网易云音乐api接口" tabindex="-1">网易云音乐API接口 <a class="header-anchor" href="#网易云音乐api接口" aria-label="Permalink to &quot;网易云音乐API接口&quot;">​</a></h3><p>网易云音乐 <code>NodeJs</code> 版 <code>API</code>,具备登陆接口,多达200多个接口,文档也写得很好,非常给不会写后端且没有项目经验的同学。</p><h2 id="emoji表情" tabindex="-1">Emoji表情 <a class="header-anchor" href="#emoji表情" aria-label="Permalink to &quot;Emoji表情&quot;">​</a></h2><p><a href="https://www.emojiall.com/zh-hans/all-cate" target="_blank" rel="noreferrer">🗂 Emoji全部分类 | EmojiAll</a></p>',82),i=[l];function c(p,h,d,m,u,b){return o(),e("div",null,i)}const k=a(s,[["render",c]]);export{f as __pageData,k as default};
